import json,re
from collections import Counter
rows=[json.loads(l) for l in open('sourcery.jsonl')]
c=Counter(); tbl=0
for r in rows:
    for p in re.split(r'^## ',r['article'],flags=re.M)[1:]:
        if p.startswith('Evidence Map'):
            m=re.search(r'^\|(.+)\|\s*$',p,re.M)
            if m: c[m.group(1).strip()]+=1; tbl+=1
print('EM with table:',tbl)
for k,v in c.most_common(6): print(v,'|',k[:150])
EOF
